mapper.select:
select CONCAT(CONVERT(varchar(10), a.tran_date, 23), ' - ', a.seq) AS tranDateSeq , a.tran_date , a.seq , c.code_nm as tranTypeName , d.storage_name as srcStorageName , min(b.item_name)+ case when count(distinct b.item_cd) > 1 then ' 외 ' + cast(count(distinct b.item_cd) - 1 as varchar(10)) + '건' else '' end as item_name , sum(b.qty) as qty , u.member_nm as managerName , a.manager_id , a.etc , a.tran_type_cd , a.src_storage_cd , a.tran_id from tb_inv_tran_mst a inner join tb_inv_tran_item b on a.tran_id = b.tran_id inner join tb_common_code c on c.code = a.tran_type_cd and c.com_type_cd = 'TRAN_CD' inner join tb_users u on u.user_id = a.manager_id left outer join tb_storage_mst d on d.storage_cd = a.src_storage_cd where a.tran_date between #{strDate} and #{endDate}
and a.tran_type_cd = #{tranTypeCd}
and a.tran_type_cd in ('P','Q','R','S','T','U','V','W','X')
and a.src_storage_cd = #{srcStorageCd}
and b.item_cd like '%' + #{itemCd} + '%'
and b.item_name like '%' + #{itemName} + '%'
group by a.tran_date, a.seq, c.code_nm, d.storage_name, u.member_nm,a.manager_id, a.etc, a.tran_type_cd, a.src_storage_cd, a.tran_id order by a.tran_date desc, a.seq desc

mapper.update:
update tb_inv_tran_item
set    qty = #{qty}
      ,upd_id = #{userId}
      ,upd_dt = getdate()
where  tran_id = #(tranId)
